import type { HTMLArkProps } from '@ark-ui/react/factory';
import { ark } from '@ark-ui/react/factory';
import { clsx } from 'clsx';
import { forwardRef, type ComponentRef } from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './Alert.module.css';

type AlertStatus = 'neutral' | 'info' | 'success' | 'warning' | 'error';

type AlertRootProps = HTMLArkProps<'div'> & {
  status?: AlertStatus;
};

const AlertRoot = forwardRef<ComponentRef<typeof ark.div>, AlertRootProps>(function AlertRoot(
  { children, className, role, status = 'neutral', ...props },
  ref,
) {
  return (
    <ark.div
      ref={ref}
      role={role ?? (status === 'error' ? 'alert' : 'status')}
      data-scope="alert"
      data-part="root"
      data-slot="alert-root"
      data-status={status}
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    >
      {children}
    </ark.div>
  );
});

const AlertIndicator = forwardRef<ComponentRef<typeof ark.span>, HTMLArkProps<'span'>>(
  function AlertIndicator({ className, ...props }, ref) {
    return (
      <ark.span
        ref={ref}
        data-scope="alert"
        data-part="indicator"
        data-slot="alert-indicator"
        aria-hidden="true"
        className={clsx(styles.indicator, normalizeClassName(className))}
        {...props}
      />
    );
  },
);

const AlertContent = forwardRef<ComponentRef<typeof ark.div>, HTMLArkProps<'div'>>(
  function AlertContent({ className, ...props }, ref) {
    return (
      <ark.div
        ref={ref}
        data-scope="alert"
        data-part="content"
        data-slot="alert-content"
        className={clsx(styles.content, normalizeClassName(className))}
        {...props}
      />
    );
  },
);

const AlertTitle = forwardRef<ComponentRef<typeof ark.p>, HTMLArkProps<'p'>>(function AlertTitle(
  { className, ...props },
  ref,
) {
  return (
    <ark.p
      ref={ref}
      data-scope="alert"
      data-part="title"
      data-slot="alert-title"
      className={clsx(styles.title, normalizeClassName(className))}
      {...props}
    />
  );
});

const AlertDescription = forwardRef<ComponentRef<typeof ark.div>, HTMLArkProps<'div'>>(
  function AlertDescription({ className, ...props }, ref) {
    return (
      <ark.div
        ref={ref}
        data-scope="alert"
        data-part="description"
        data-slot="alert-description"
        className={clsx(styles.description, normalizeClassName(className))}
        {...props}
      />
    );
  },
);

const AlertActions = forwardRef<ComponentRef<typeof ark.div>, HTMLArkProps<'div'>>(
  function AlertActions({ className, ...props }, ref) {
    return (
      <ark.div
        ref={ref}
        data-scope="alert"
        data-part="actions"
        data-slot="alert-actions"
        className={clsx(styles.actions, normalizeClassName(className))}
        {...props}
      />
    );
  },
);

const Alert = Object.assign(AlertRoot, {
  Root: AlertRoot,
  Indicator: AlertIndicator,
  Content: AlertContent,
  Title: AlertTitle,
  Description: AlertDescription,
  Actions: AlertActions,
});

export { Alert };

@layer moduix.components {
  .root {
    box-sizing: border-box;
    display: grid;
    grid-template-columns: auto minmax(0, 1fr);
    align-items: start;
    width: 100%;
    min-width: 0;
    row-gap: var(--moduix-alert-content-gap, var(--moduix-spacing-1));
    column-gap: var(--moduix-alert-gap, var(--moduix-spacing-3));
    border: var(--moduix-alert-border-width, var(--moduix-border-width-sm)) solid
      var(
        --moduix-alert-border-color,
        var(--moduix-alert-border-color-default, var(--moduix-color-border))
      );
    border-radius: var(--moduix-alert-radius, var(--moduix-radius-lg));
    padding: var(--moduix-alert-padding, var(--moduix-spacing-3));
    background-color: var(
      --moduix-alert-bg,
      var(--moduix-alert-bg-default, var(--moduix-color-card))
    );
    color: var(
      --moduix-alert-color,
      var(--moduix-alert-color-default, var(--moduix-color-card-foreground))
    );
    box-shadow: var(--moduix-alert-shadow, none);

    > [data-part='title'],
    > [data-part='description'] {
      grid-column: 2;
    }

    &[data-status='neutral'] {
      --moduix-alert-bg-default: var(--moduix-color-card);
      --moduix-alert-border-color-default: var(--moduix-color-border);
      --moduix-alert-color-default: var(--moduix-color-card-foreground);
      --moduix-alert-indicator-color-default: var(--moduix-color-muted-foreground);
    }

    &[data-status='info'] {
      --moduix-alert-bg-default: color-mix(
        in oklab,
        var(--moduix-color-primary) 4%,
        var(--moduix-color-background)
      );
      --moduix-alert-border-color-default: color-mix(
        in oklab,
        var(--moduix-color-primary) 32%,
        transparent
      );
      --moduix-alert-color-default: var(--moduix-color-foreground);
      --moduix-alert-indicator-color-default: var(--moduix-color-primary);
    }

    &[data-status='success'] {
      --moduix-alert-bg-default: color-mix(
        in oklab,
        var(--moduix-color-success) 10%,
        var(--moduix-color-background)
      );
      --moduix-alert-border-color-default: color-mix(
        in oklab,
        var(--moduix-color-success) 34%,
        transparent
      );
      --moduix-alert-color-default: var(--moduix-color-foreground);
      --moduix-alert-indicator-color-default: var(--moduix-color-success);
    }

    &[data-status='warning'] {
      --moduix-alert-bg-default: color-mix(
        in oklab,
        var(--moduix-color-warning) 13%,
        var(--moduix-color-background)
      );
      --moduix-alert-border-color-default: color-mix(
        in oklab,
        var(--moduix-color-warning) 38%,
        transparent
      );
      --moduix-alert-color-default: var(--moduix-color-foreground);
      --moduix-alert-indicator-color-default: var(--moduix-color-warning);
    }

    &[data-status='error'] {
      --moduix-alert-bg-default: color-mix(
        in oklab,
        var(--moduix-color-destructive) 9%,
        var(--moduix-color-background)
      );
      --moduix-alert-border-color-default: color-mix(
        in oklab,
        var(--moduix-color-destructive) 35%,
        transparent
      );
      --moduix-alert-color-default: var(--moduix-color-foreground);
      --moduix-alert-indicator-color-default: var(--moduix-color-destructive);
    }

    &:not(:has(> [data-part='indicator'])) {
      grid-template-columns: minmax(0, 1fr);

      > [data-part='content'],
      > [data-part='title'],
      > [data-part='description'] {
        grid-column: 1;
      }
    }
  }

  .indicator {
    display: inline-flex;
    width: var(--moduix-alert-indicator-size, var(--moduix-spacing-4));
    height: var(--moduix-alert-indicator-size, var(--moduix-spacing-4));
    align-items: center;
    justify-content: center;
    color: var(
      --moduix-alert-indicator-color,
      var(--moduix-alert-indicator-color-default, currentColor)
    );
    margin-block-start: var(--moduix-alert-indicator-offset, var(--moduix-spacing-0-5));

    & :where(svg) {
      width: var(--moduix-alert-indicator-size, var(--moduix-spacing-4));
      height: var(--moduix-alert-indicator-size, var(--moduix-spacing-4));
      flex-shrink: 0;
      pointer-events: none;
    }
  }

  .content {
    display: grid;
    min-width: 0;
    gap: var(--moduix-alert-content-gap, var(--moduix-spacing-1));
  }

  .title {
    margin: 0;
    min-width: 0;
    color: var(
      --moduix-alert-title-color,
      var(--moduix-alert-color, var(--moduix-alert-color-default))
    );
    font-size: var(--moduix-alert-title-font-size, var(--moduix-text-sm));
    font-weight: var(--moduix-alert-title-font-weight, var(--moduix-weight-semibold));
    line-height: var(--moduix-alert-title-line-height, var(--moduix-line-height-text-sm));
    overflow-wrap: anywhere;
  }

  .description {
    min-width: 0;
    color: var(--moduix-alert-description-color, var(--moduix-color-muted-foreground));
    font-size: var(--moduix-alert-description-font-size, var(--moduix-text-sm));
    line-height: var(--moduix-alert-description-line-height, var(--moduix-line-height-text-sm));
    overflow-wrap: anywhere;

    & > :first-child {
      margin-top: 0;
    }

    & > :last-child {
      margin-bottom: 0;
    }
  }

  .actions {
    display: flex;
    flex-wrap: wrap;
    margin-block-start: var(--moduix-alert-actions-margin-top, var(--moduix-spacing-2));
    gap: var(--moduix-alert-actions-gap, var(--moduix-spacing-2));
  }
}
